// Check soil parameters against thresholds
const thresholds = {
    organic_matter: { min: 2.0, optimal: 3.0 },
    ph_level: { min: 6.0, max: 7.5, optimal: 6.8 },
    nitrogen: { min: 30, optimal: 50 }
};

const soil = msg.payload;
const alerts = [];

// Check organic matter
if (soil.organic_matter < thresholds.organic_matter.min) {
    alerts.push(`Low organic matter: ${soil.organic_matter}% (min: ${thresholds.organic_matter.min}%)`);
}

// Check pH
if (soil.ph_level < thresholds.ph_level.min || soil.ph_level > thresholds.ph_level.max) {
    alerts.push(`pH out of range: ${soil.ph_level} (optimal: ${thresholds.ph_level.optimal})`);
}

// Check nitrogen
if (soil.nitrogen < thresholds.nitrogen.min) {
    alerts.push(`Low nitrogen: ${soil.nitrogen} ppm (min: ${thresholds.nitrogen.min} ppm)`);
}

// Add cache info
if (soil.cache_info && soil.cache_info.stale) {
    alerts.push(`⚠️ Using stale data (${Math.floor(soil.cache_info.age_seconds / 3600)} hours old)`);
}

// Create alert message
if (alerts.length > 0) {
    msg.payload = {
        alert: true,
        county_fips: soil.county_fips,
        timestamp: new Date().toISOString(),
        issues: alerts,
        soil_data: soil
    };
    msg.topic = "soil/alert";
} else {
    msg.payload = {
        alert: false,
        county_fips: soil.county_fips,
        timestamp: new Date().toISOString(),
        message: "Soil health is good",
        soil_data: soil
    };
    msg.topic = "soil/status";
}

return msg;
